import{_ as t,o as a,c as o,a3 as s}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse('{"title":"76. Study Leave","description":"","frontmatter":{"title":"76. Study Leave","eba":"Nurses and Midwives 2024-2028","topics":["leave","study-leave","preliminary","education-pd"]},"headers":[],"relativePath":"ebas/nurses-midwives/education-pd/76-study-leave.md","filePath":"ebas/nurses-midwives/education-pd/76-study-leave.md"}'),n={name:"ebas/nurses-midwives/education-pd/76-study-leave.md"};function r(i,e,l,p,d,u){return a(),o("div",null,[...e[0]||(e[0]=[s('<h1 id="_76-study-leave" tabindex="-1">76. Study Leave <a class="header-anchor" href="#_76-study-leave" aria-label="Permalink to &quot;76. Study Leave&quot;">​</a></h1><p>This clause does not apply to casual Employees.</p><p>See <a href="/eba/ebas/allied-health/preliminary/4-definitions.html">clause 4.2</a> (Relevant qualification/relevant component of qualification etc.) for considerations relating to relevance.</p><p><strong>76.1</strong> When paid study leave is available</p><p><strong>(a)</strong> From 24 June 2024, paid study leave will be available to all Employees where a component of the course is relevant to nursing and/or midwifery.</p><p><strong>(b)</strong> Paid study leave may be taken as mutually agreed by, for example, four hours per week, eight hours per fortnight or blocks of 38 hours at a residential school.</p><p><strong>(c)</strong> A part-time Employee will be entitled to paid study leave on a pro rata basis.</p><p><strong>(d)</strong> Leave pursuant to this clause does not accumulate from year to year.</p><p><strong>76.2</strong> Application</p><p>An Employee wishing to take study leave must:</p><p><strong>(a)</strong> apply in writing to the Employer as early as possible prior to the proposed leave date; and</p><p><strong>(b)</strong> include with the application:</p><p><strong>(i)</strong> details of the course and institution in which the Employee is enrolled or proposes to enrol; and</p><p><strong>(ii)</strong> details of the relevance of the course to the Employee&#39;s employment.</p><p><strong>76.3</strong> Response to application</p><p><strong>(a)</strong> The Employer will not unreasonably refuse a request for study leave.</p><p><strong>(b)</strong> The Employer must, within seven days of the application being made, notify the Employee in writing whether the application for study leave has been approved.</p><p>Plain language terms: exam leave, education leave.</p>',18)])])}const m=t(n,[["render",r]]);export{h as __pageData,m as default};
